/**
 * иБФзљСжРЬзіҐ Provider еЫЊж†ЗзїДдїґеЕ•еПВгАВ
 */
type WebSearchProviderIconProps = {
  /** иБФзљСжРЬзіҐ Provider ж†ЗиѓЖгАВ */
  pid?: string;
  /** е§Це±ВйЩДеК†з±їеРНпЉМйїШиЃ§дљњзФ® `h-4 w-4`гАВ */
  className?: string;
} & Omit<SvgIconProps, 'className'>;

/**
 * жМЙиБФзљСжРЬзіҐ Provider з±їеЮЛжЄ≤жЯУеѓєеЇФеЫЊж†ЗгАВ
 *
 * иѓіжШОпЉЪ
 * - еѓєеЈ≤зЯ• Provider дљњзФ®еУБзЙМеЫЊж†ЗпЉЫ
 * - жЬ™иѓЖеИЂзЪД Provider зїЯдЄАеЫЮйААдЄЇйАЪзФ®еЬ∞зРГеЫЊж†ЗпЉМйБњеЕНеЫ†дЄЇйЕНзљЃжЙ©е±ХиАМеЗЇзО∞з©ЇзЩљеН†дљНгАВ
 */
export function WebSearchProviderIcon({
  pid,
  className,
  ...rest
}: WebSearchProviderIconProps) {
  const id = String(pid || '').trim();
  const common = { className: className || 'h-4 w-4', ...rest };

  switch (id) {
    case 'local-google':
      return <GoogleIcon {...common} />;
    case 'local-bing':
      return <BingIcon {...common} />;
    case 'local-baidu':
      return <BaiduIcon {...common} />;
    case 'exa':
    case 'exa-mcp':
      return <ExaIcon {...common} />;
    case 'tavily':
      return <TavilyIcon {...common} />;
    case 'zhipu':
      return <ZhipuIcon {...common} />;
    case 'searxng':
      return <SearXngIcon {...common} />;
    case 'bocha':
      return <BochaIcon {...common} />;
    default:
      return <Globe className={common.className} />;
  }
}
